mapper.select:
SELECT /* getReadingGoalDtl */
       G.USER_NUMB
     , G.GOAL_DATE
     , G.GOAL_TYPE
     , G.GOAL_CNTT AS GOAL_CNT
     , NVL(G.UPDT_CNTT, 0) AS UPDT_CNTT
  FROM TM_GOALXM G
 WHERE G.USER_NUMB = #{userNumb}
   AND G.GOAL_DATE = #{goalDate}
   AND G.GOAL_TYPE = #{goalType}


SELECT /* getPublicReportLikeTargetCnt */
       COUNT(*)
 FROM TM_REPORT R
 WHERE R.REPT_NUMB = #{reptNumb}
   AND (
       R.USER_NUMB = #{userNumb}
    OR R.PUBC_YSNO = #{commYes}
   )

SELECT /* dupReportLike */
       COUNT(*)
  FROM TB_RPLIKE
 WHERE USER_NUMB = #{userNumb}
   AND REPT_NUMB = #{reptNumb}

