 WHERE USER_NUMB = #{userNumb}
   AND REPT_NUMB = #{reptNumb}

mapper.insert:

    SELECT TM_REPORT_SEQ.NEXTVAL FROM DUAL

/* setReport */
INSERT INTO TM_REPORT(
            REPT_NUMB
          , USER_NUMB
          , BOOK_NUMB
          , REPT_STAT
          , REPT_STDT
          , REPT_ENDT
          , REPT_GRDE
          , REPT_COLR
          , PUBC_YSNO
          , REPT_CNTN
          , REGI_DATE
          , UPDT_DATE
) VALUES (  #{reptNumb}
          , #{userNumb}
          , #{bookNumb}
          , #{reptStat}
          , #{reptStdt}
          , #{reptEndt}
          , #{reptGrde}
          , #{reptColr}
          , #{pubcYsno}
          , #{reptCntn}
          , SYSDATE
          , SYSDATE
)

mapper.update:
/* uptReport */
UPDATE TM_REPORT
   SET REPT_STAT = #{reptStat}
     , REPT_STDT = #{reptStdt}
     , REPT_ENDT = #{reptEndt}
     , REPT_GRDE = #{reptGrde}
     , REPT_COLR = #{reptColr}
     , PUBC_YSNO = #{pubcYsno}
     , REPT_CNTN = #{reptCntn}
     , UPDT_DATE = SYSDATE
 WHERE REPT_NUMB = #{reptNumb}
   AND USER_NUMB = #{userNumb}

/* uptReptStatusGrade */
UPDATE TM_REPORT

       REPT_STAT = #{reptStat}
     , REPT_GRDE = #{reptGrde}

     , REPT_ENDT = #{reptEndt}

     , UPDT_DATE = SYSDATE

 WHERE REPT_NUMB = #{reptNumb}
   AND USER_NUMB = #{userNumb}

mapper.delete:
/* delReport */
DELETE FROM TM_REPORT
 WHERE REPT_NUMB = #{reptNumb}
   AND USER_NUMB = #{userNumb}
